255→					// Imports of a same package are all mapped in the same scope, so we cannot just
256→					// map them by their names, otherwise we could have collisions from same-name
257→					// imports in different source files of the same package. Therefore, we suffix
258→					// the key with the basename of the source file.
259→					name = path.Join(name, baseName)
