322→				return false
323→			}
324→
325→			if n.kind == typeSpecAssign {
326→				// Create an aliased type in the current scope
327→				sc.sym[typeName] = &symbol{kind: typeSym, node: n, typ: typ}
328→				n.typ = typ
329→				break
330→			}
331→
332→			// else we are not an alias (typeSpec)
333→
334→			switch n.child[1].kind {
335→			case identExpr, selectorExpr:
336→				n.typ = namedOf(typ, pkgName, typeName, withNode(n.child[0]), withScope(sc))
337→				n.typ.incomplete = typ.incomplete
338→				n.typ.field = typ.field
339→				copy(n.typ.method, typ.method)
340→			default:
341→				n.typ = typ
342→				n.typ.name = typeName
343→				n.typ.path = pkgName
344→			}
345→			n.typ.str = n.typ.path + "." + n.typ.name
346→
347→			asImportName := path.Join(typeName, baseName)
