	"fmt"
	"go/ast"
	"io/fs"
	"path"
	"sort"
	"strings"
	"time"
)

// embedDir stores embed directive info for a variable declaration.
type embedDir struct {
	patterns []string // combined patterns from all //go:embed lines
}

// parseEmbedDirectives scans a Go source file's comments to extract //go:embed
// directives and maps them to the variable declarations they annotate.
// It returns a map from the token position of the variable's GenDecl to the
// combined embed patterns.
func parseEmbedDirectives(f *ast.File) map[*ast.GenDecl]*embedDir {
	if f == nil {
		return nil
	}

	result := map[*ast.GenDecl]*embedDir{}

