// matchEmbedPattern matches a single pattern against the filesystem.
func matchEmbedPattern(filesystem fs.FS, srcDir, pattern string, includeHidden bool) (map[string][]byte, error) {
	result := map[string][]byte{}

	// Resolve pattern relative to srcDir
	fullPattern := path.Join(srcDir, pattern)

	// Check if the pattern refers to a directory
	if fi, err := fs.Stat(filesystem, fullPattern); err == nil && fi.IsDir() {
		// Embed entire directory tree
		return embedDirTree(filesystem, srcDir, pattern, includeHidden)
	}

	// Glob match
	matches, err := fs.Glob(filesystem, fullPattern)
	if err != nil {
		return nil, err
	}

	for _, match := range matches {
		// Get the path relative to srcDir
		rel := strings.TrimPrefix(match, srcDir+"/")
		if rel == match && srcDir != "." && srcDir != "" {
			// match didn't start with srcDir
			continue
		}
		if srcDir == "." || srcDir == "" {
			rel = match
		}

		if !includeHidden && isHiddenOrUnderscore(rel) {
			continue
		}

		fi, err := fs.Stat(filesystem, match)
		if err != nil {
			return nil, err
		}
		if fi.IsDir() {
			// If glob matches a directory, embed its tree
			dirFiles, err := embedDirTree(filesystem, srcDir, rel, includeHidden)
			if err != nil {
				return nil, err
			}
			for k, v := range dirFiles {
				result[k] = v
			}
			continue
		}

		data, err := fs.ReadFile(filesystem, match)
		if err != nil {
			return nil, err
		}
		result[rel] = data
	}

	return result, nil
}

// embedDirTree recursively embeds all files in a directory tree.
func embedDirTree(filesystem fs.FS, srcDir, dirRel string, includeHidden bool) (map[string][]byte, error) {
	result := map[string][]byte{}
	dirFull := path.Join(srcDir, dirRel)

	err := fs.WalkDir(filesystem, dirFull, func(p string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}

		rel := strings.TrimPrefix(p, srcDir+"/")
		if rel == p && srcDir != "." && srcDir != "" {
			return nil
		}
		if srcDir == "." || srcDir == "" {
			rel = p
		}

		if !includeHidden && d.Name() != "." && isHiddenOrUnderscore(d.Name()) {
			if d.IsDir() {
				return fs.SkipDir
			}
			return nil
		}

		if d.IsDir() {
			return nil
		}

		data, err := fs.ReadFile(filesystem, p)
		if err != nil {
			return err
		}
		result[rel] = data
		return nil
	})

	return result, err
}

// isHiddenOrUnderscore returns true if the base name starts with "." or "_".
func isHiddenOrUnderscore(name string) bool {
	base := path.Base(name)
	return strings.HasPrefix(base, ".") || strings.HasPrefix(base, "_")
}

// embedFS implements fs.FS, fs.ReadFileFS, and fs.ReadDirFS for embedded files.
type embedFS struct {
	files map[string][]byte // path -> content
}

// newEmbedFS creates an embedFS from a map of file paths to contents.
func newEmbedFS(files map[string][]byte) *embedFS {
	return &embedFS{files: files}
}

// Open implements fs.FS.
func (f *embedFS) Open(name string) (fs.File, error) {
	if !fs.ValidPath(name) {
		return nil, &fs.PathError{Op: "open", Path: name, Err: fs.ErrInvalid}
	}

	// Check if it's a file
	if data, ok := f.files[name]; ok {
		return &embedFile{
			name: path.Base(name),
			data: data,
		}, nil
	}

	// Check if it's a directory (root "." or a prefix of some files)
	if name == "." || f.isDir(name) {
		return &embedDirFile{
			name:  path.Base(name),
			fs:    f,
			dir:   name,
			isRoot: name == ".",
		}, nil
	}

	return nil, &fs.PathError{Op: "open", Path: name, Err: fs.ErrNotExist}
}

// ReadFile implements fs.ReadFileFS.
func (f *embedFS) ReadFile(name string) ([]byte, error) {
	if !fs.ValidPath(name) {
		return nil, &fs.PathError{Op: "read", Path: name, Err: fs.ErrInvalid}
	}

	data, ok := f.files[name]
	if !ok {
		return nil, &fs.PathError{Op: "read", Path: name, Err: fs.ErrNotExist}
	}

	// Return an independent copy
	cp := make([]byte, len(data))
	copy(cp, data)
	return cp, nil
}

// ReadDir implements fs.ReadDirFS.
func (f *embedFS) ReadDir(name string) ([]fs.DirEntry, error) {
	if !fs.ValidPath(name) {
		return nil, &fs.PathError{Op: "readdir", Path: name, Err: fs.ErrInvalid}
	}

	if name != "." && !f.isDir(name) {
		return nil, &fs.PathError{Op: "readdir", Path: name, Err: fs.ErrNotExist}
	}

	return f.readDir(name), nil
}

func (f *embedFS) isDir(name string) bool {
	prefix := name + "/"
	for p := range f.files {
		if strings.HasPrefix(p, prefix) {
			return true
		}
		// Also check if any intermediate directory matches
	}
	// Check for intermediate directories: if any file's path has this as
	// a directory component, it's a valid directory.
	for p := range f.files {
		dir := p
		for {
			dir = path.Dir(dir)
			if dir == "." || dir == "" {
				break
			}
			if dir == name {
				return true
			}
		}
	}
	return false
}

func (f *embedFS) readDir(name string) []fs.DirEntry {
	seen := map[string]bool{}
	var entries []fs.DirEntry

	prefix := ""
	if name != "." {
		prefix = name + "/"
	}

	for p, data := range f.files {
		if !strings.HasPrefix(p, prefix) && prefix != "" {
			continue
		}

		rel := strings.TrimPrefix(p, prefix)
		if rel == "" {
			continue
		}

		// Get the immediate child name
		parts := strings.SplitN(rel, "/", 2)
		childName := parts[0]

		if seen[childName] {
			continue
		}
		seen[childName] = true

		if len(parts) > 1 {
			// It's a directory
			entries = append(entries, &embedDirEntry{
				name:  childName,
				isDir: true,
			})
		} else {
			// It's a file
			entries = append(entries, &embedDirEntry{
				name:  childName,
				isDir: false,
				size:  int64(len(data)),
			})
		}
	}

	sort.Slice(entries, func(i, j int) bool {
		return entries[i].Name() < entries[j].Name()
	})
	return entries
}

// embedFile implements fs.File for a regular file.
type embedFile struct {
	name   string
	data   []byte
	offset int
}

func (f *embedFile) Stat() (fs.FileInfo, error) {
	return &embedFileInfo{name: f.name, size: int64(len(f.data))}, nil
}

func (f *embedFile) Read(b []byte) (int, error) {
	if f.offset >= len(f.data) {
		return 0, fmt.Errorf("EOF")
	}
	n := copy(b, f.data[f.offset:])
	f.offset += n
	return n, nil
}

func (f *embedFile) Close() error { return nil }

// embedDirFile implements fs.File and fs.ReadDirFile for a directory.
type embedDirFile struct {
	name    string
	fs      *embedFS
	dir     string
	isRoot  bool
	entries []fs.DirEntry
	offset  int
}

func (f *embedDirFile) Stat() (fs.FileInfo, error) {
	return &embedFileInfo{name: f.name, isDir: true}, nil
}

func (f *embedDirFile) Read([]byte) (int, error) {
	return 0, &fs.PathError{Op: "read", Path: f.name, Err: fmt.Errorf("is a directory")}
}

func (f *embedDirFile) Close() error { return nil }

func (f *embedDirFile) ReadDir(n int) ([]fs.DirEntry, error) {
	if f.entries == nil {
		f.entries = f.fs.readDir(f.dir)
	}

	if n <= 0 {
		entries := f.entries[f.offset:]
		f.offset = len(f.entries)
		return entries, nil
	}

	if f.offset >= len(f.entries) {
		return nil, fmt.Errorf("EOF")
	}

	end := f.offset + n
	if end > len(f.entries) {
		end = len(f.entries)
	}
	entries := f.entries[f.offset:end]
	f.offset = end

	if f.offset >= len(f.entries) {
		return entries, fmt.Errorf("EOF")
	}
	return entries, nil
}

// embedDirEntry implements fs.DirEntry.
type embedDirEntry struct {
	name  string
	isDir bool
	size  int64
}

func (e *embedDirEntry) Name() string               { return e.name }
func (e *embedDirEntry) IsDir() bool                 { return e.isDir }
func (e *embedDirEntry) Type() fs.FileMode           { if e.isDir { return fs.ModeDir }; return 0 }
func (e *embedDirEntry) Info() (fs.FileInfo, error)   { return &embedFileInfo{name: e.name, isDir: e.isDir, size: e.size}, nil }

// embedFileInfo implements fs.FileInfo.
type embedFileInfo struct {
	name  string
	size  int64
	isDir bool
}

func (fi *embedFileInfo) Name() string      { return fi.name }
func (fi *embedFileInfo) Size() int64       { return fi.size }
func (fi *embedFileInfo) Mode() fs.FileMode { if fi.isDir { return fs.ModeDir | 0555 }; return 0444 }
func (fi *embedFileInfo) ModTime() time.Time { return time.Time{} }
func (fi *embedFileInfo) IsDir() bool        { return fi.isDir }
func (fi *embedFileInfo) Sys() interface{}   { return nil }

