package interp

import (
	"fmt"
	"go/ast"
	"io/fs"
	"path"
	"sort"
	"strings"
	"time"
)

// embedDir stores embed directive info for a variable declaration.
type embedDir struct {
	patterns []string // combined patterns from all //go:embed lines
}

// parseEmbedDirectives scans a Go source file's comments to extract //go:embed
// directives and maps them to the variable declarations they annotate.
// It returns a map from the token position of the variable's GenDecl to the
// combined embed patterns.
func parseEmbedDirectives(f *ast.File) map[*ast.GenDecl]*embedDir {
	if f == nil {
		return nil
	}

	result := map[*ast.GenDecl]*embedDir{}

	// Build a map of comment end position -> embed patterns.
	// A //go:embed comment appears as a standalone line comment just before
	// a var declaration. The Go parser attaches them to CommentGroups.
	// We map them by line position.
	type embedComment struct {
		endLine  int      // line after the last //go:embed line
		patterns []string // collected patterns
	}
	var embedComments []embedComment

	for _, cg := range f.Comments {
		var patterns []string
		for _, c := range cg.List {
			text := c.Text
			if !strings.HasPrefix(text, "//go:embed ") {
				continue
			}
			args := strings.TrimPrefix(text, "//go:embed ")
			for _, p := range strings.Fields(args) {
				patterns = append(patterns, p)
			}
		}
		if len(patterns) > 0 {
			// The embed comment group ends at some line; the var decl
			// should follow immediately after.
			embedComments = append(embedComments, embedComment{
				endLine:  f.Fset.Position(cg.End()).Line,
				patterns: patterns,
			})
		}
	}

	if len(embedComments) == 0 {
		return nil
	}

	// Match embed comments to var declarations.
	// A //go:embed directive applies to the var declaration on the
	// immediately following line(s).
	for _, decl := range f.Decls {
		gd, ok := decl.(*ast.GenDecl)
		if !ok || gd.Tok.String() != "var" {
			continue
		}

		declLine := f.Fset.Position(gd.Pos()).Line

		// Collect all embed comments that end just before this declaration.
		var allPatterns []string
		for _, ec := range embedComments {
			// The embed comment should be on the line(s) immediately before
			// the var declaration. Allow for the declaration to start on the
			// line right after the comment ends.
			if ec.endLine == declLine-1 || ec.endLine == declLine {
				allPatterns = append(allPatterns, ec.patterns...)
			}
		}

		if len(allPatterns) > 0 {
			result[gd] = &embedDir{patterns: allPatterns}
		}
	}

	return result
}

// parseEmbedDirectivesGrouped handles grouped var blocks: var ( ... )
// Inside a grouped block, each ValueSpec can have its own //go:embed lines.
// Returns a map from ValueSpec position to embed patterns.
func parseEmbedDirectivesGrouped(f *ast.File, gd *ast.GenDecl) map[*ast.ValueSpec]*embedDir {
	if f == nil || gd == nil || !gd.Lparen.IsValid() {
		return nil
	}

	result := map[*ast.ValueSpec]*embedDir{}

	// Collect all embed comments in the file with their line positions.
	type embedComment struct {
		endLine  int
		patterns []string
	}
	var embedComments []embedComment

	for _, cg := range f.Comments {
		var patterns []string
		for _, c := range cg.List {
			text := c.Text
			if !strings.HasPrefix(text, "//go:embed ") {
				continue
			}
			args := strings.TrimPrefix(text, "//go:embed ")
			for _, p := range strings.Fields(args) {
				patterns = append(patterns, p)
			}
		}
		if len(patterns) > 0 {
			embedComments = append(embedComments, embedComment{
				endLine:  f.Fset.Position(cg.End()).Line,
				patterns: patterns,
			})
		}
	}

	if len(embedComments) == 0 {
		return nil
	}

	for _, spec := range gd.Specs {
		vs, ok := spec.(*ast.ValueSpec)
		if !ok {
			continue
		}

