}

// parseEmbedDirectives2 scans a Go source file's comments to extract //go:embed
// directives and maps them to the var GenDecl they annotate.
func parseEmbedDirectives2(fset *token.FileSet, f *ast.File) map[*ast.GenDecl]*embedDir {
	if f == nil {
		return nil
	}

	embedComments := collectEmbedComments(fset, f)
	if len(embedComments) == 0 {
		return nil
	}

