// (relative to the source dir) and their contents.
func resolveEmbedPatterns(filesystem fs.FS, srcDir string, patterns []string) (map[string][]byte, error) {
	files := map[string][]byte{}

	for _, pattern := range patterns {
		includeHidden := false
		p := pattern
		if strings.HasPrefix(p, "all:") {
			includeHidden = true
			p = strings.TrimPrefix(p, "all:")
		}

		// Validate the pattern.
