package interp

import (
	"fmt"
	"go/ast"
	"go/token"
	"io"
	"io/fs"
	"path"
	"sort"
	"strings"
	"time"
)

// embedDir stores embed directive info for a variable declaration.
type embedDir struct {
	patterns []string // combined patterns from all //go:embed lines
}

// collectEmbedComments extracts //go:embed line comments from a file's comment groups.
// Returns a list of (endLine, patterns) pairs.
type embedComment struct {
	endLine  int      // line number of the last //go:embed line in this group
	patterns []string // collected patterns
}

func collectEmbedComments(fset *token.FileSet, f *ast.File) []embedComment {
	var result []embedComment

	for _, cg := range f.Comments {
		var patterns []string
		for _, c := range cg.List {
			text := c.Text
			if !strings.HasPrefix(text, "//go:embed ") {
				continue
			}
			args := strings.TrimPrefix(text, "//go:embed ")
			for _, p := range strings.Fields(args) {
				patterns = append(patterns, p)
			}
		}
		if len(patterns) > 0 {
			result = append(result, embedComment{
				endLine:  fset.Position(cg.End()).Line,
				patterns: patterns,
			})
		}
	}

	return result
}

// parseEmbedDirectives2 scans a Go source file's comments to extract //go:embed
// directives and maps them to the var GenDecl they annotate.
func parseEmbedDirectives2(fset *token.FileSet, f *ast.File) map[*ast.GenDecl]*embedDir {
	if f == nil {
		return nil
	}

	embedComments := collectEmbedComments(fset, f)
	if len(embedComments) == 0 {
		return nil
	}

	result := map[*ast.GenDecl]*embedDir{}

	for _, decl := range f.Decls {
		gd, ok := decl.(*ast.GenDecl)
		if !ok || gd.Tok != token.VAR {
			continue
		}

		declLine := fset.Position(gd.Pos()).Line

		var allPatterns []string
		for _, ec := range embedComments {
			if ec.endLine == declLine-1 || ec.endLine == declLine {
				allPatterns = append(allPatterns, ec.patterns...)
			}
		}

		if len(allPatterns) > 0 {
			result[gd] = &embedDir{patterns: allPatterns}
		}
	}

	if len(result) == 0 {
		return nil
	}
	return result
}

// parseEmbedDirectivesGrouped2 handles grouped var blocks: var ( ... )
// Inside a grouped block, each ValueSpec can have its own //go:embed lines.
func parseEmbedDirectivesGrouped2(fset *token.FileSet, f *ast.File, gd *ast.GenDecl) map[*ast.ValueSpec]*embedDir {
	if f == nil || gd == nil || !gd.Lparen.IsValid() {
		return nil
	}

	embedComments := collectEmbedComments(fset, f)
	if len(embedComments) == 0 {
		return nil
	}

	result := map[*ast.ValueSpec]*embedDir{}

	for _, spec := range gd.Specs {
		vs, ok := spec.(*ast.ValueSpec)
		if !ok {
			continue
		}

		specLine := fset.Position(vs.Pos()).Line

		var allPatterns []string
		for _, ec := range embedComments {
			if ec.endLine == specLine-1 || ec.endLine == specLine {
				allPatterns = append(allPatterns, ec.patterns...)
			}
		}

		if len(allPatterns) > 0 {
			result[vs] = &embedDir{patterns: allPatterns}
		}
	}

	if len(result) == 0 {
		return nil
	}
	return result
}

// resolveEmbedPatterns resolves embed patterns against a filesystem, relative
// to the source file's directory. It returns the matched file paths
// (relative to the source dir) and their contents.
func resolveEmbedPatterns(filesystem fs.FS, srcDir string, patterns []string) (map[string][]byte, error) {
	files := map[string][]byte{}

	for _, pattern := range patterns {
		includeHidden := false
		p := pattern
		if strings.HasPrefix(p, "all:") {
			includeHidden = true
			p = strings.TrimPrefix(p, "all:")
		}

		// Validate the pattern.
		if _, err := path.Match(p, ""); err != nil {
			return nil, fmt.Errorf("invalid pattern syntax %q", pattern)
		}

		matched, err := matchEmbedPattern(filesystem, srcDir, p, includeHidden)
		if err != nil {
			return nil, fmt.Errorf("pattern %s: %v", pattern, err)
		}

		if len(matched) == 0 {
			return nil, fmt.Errorf("pattern %s: no matching files found", pattern)
		}

		for name, data := range matched {
			files[name] = data
		}
	}

	return files, nil
}

// matchEmbedPattern matches a single pattern against the filesystem.
func matchEmbedPattern(filesystem fs.FS, srcDir, pattern string, includeHidden bool) (map[string][]byte, error) {
	result := map[string][]byte{}

	fullPattern := path.Join(srcDir, pattern)

	// Check if the pattern refers to a directory.
	if fi, err := fs.Stat(filesystem, fullPattern); err == nil && fi.IsDir() {
		return embedDirTree(filesystem, srcDir, pattern, includeHidden)
	}

	matches, err := fs.Glob(filesystem, fullPattern)
	if err != nil {
		return nil, err
	}

	for _, match := range matches {
		rel := strings.TrimPrefix(match, srcDir+"/")
		if rel == match && srcDir != "." && srcDir != "" {
			continue
		}
		if srcDir == "." || srcDir == "" {
			rel = match
		}

		if !includeHidden && isHiddenOrUnderscore(rel) {
			continue
		}

		fi, err := fs.Stat(filesystem, match)
		if err != nil {
			return nil, err
		}
		if fi.IsDir() {
			dirFiles, err := embedDirTree(filesystem, srcDir, rel, includeHidden)
			if err != nil {
				return nil, err
			}
			for k, v := range dirFiles {
				result[k] = v
			}
			continue
		}

		data, err := fs.ReadFile(filesystem, match)
		if err != nil {
			return nil, err
		}
		result[rel] = data
	}

	return result, nil
}

// embedDirTree recursively embeds all files in a directory tree.
func embedDirTree(filesystem fs.FS, srcDir, dirRel string, includeHidden bool) (map[string][]byte, error) {
	result := map[string][]byte{}
	dirFull := path.Join(srcDir, dirRel)

	err := fs.WalkDir(filesystem, dirFull, func(p string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}

		rel := strings.TrimPrefix(p, srcDir+"/")
		if rel == p && srcDir != "." && srcDir != "" {
			return nil
		}
		if srcDir == "." || srcDir == "" {
			rel = p
		}

		if !includeHidden && d.Name() != "." && isHiddenOrUnderscore(d.Name()) {
			if d.IsDir() {
				return fs.SkipDir
			}
			return nil
		}

		if d.IsDir() {
			return nil
		}

		data, err := fs.ReadFile(filesystem, p)
		if err != nil {
			return err
		}
		result[rel] = data
		return nil
	})

	return result, err
}

// isHiddenOrUnderscore returns true if the base name starts with "." or "_".
func isHiddenOrUnderscore(name string) bool {
	base := path.Base(name)
	return strings.HasPrefix(base, ".") || strings.HasPrefix(base, "_")
}

// embedFS implements fs.FS, fs.ReadFileFS, and fs.ReadDirFS for embedded files.
type embedFS struct {
	files map[string][]byte // path -> content
}

// newEmbedFS creates an embedFS from a map of file paths to contents.
func newEmbedFS(files map[string][]byte) *embedFS {
	return &embedFS{files: files}
}

// Open implements fs.FS.
func (f *embedFS) Open(name string) (fs.File, error) {
	if !fs.ValidPath(name) {
		return nil, &fs.PathError{Op: "open", Path: name, Err: fs.ErrInvalid}
	}

	if data, ok := f.files[name]; ok {
		return &embedFile{
			name: path.Base(name),
			data: data,
		}, nil
	}

	if name == "." || f.isDir(name) {
		return &embedDirFile{
			name: path.Base(name),
			fs:   f,
			dir:  name,
		}, nil
	}

	return nil, &fs.PathError{Op: "open", Path: name, Err: fs.ErrNotExist}
}

// ReadFile implements fs.ReadFileFS.
func (f *embedFS) ReadFile(name string) ([]byte, error) {
	if !fs.ValidPath(name) {
		return nil, &fs.PathError{Op: "read", Path: name, Err: fs.ErrInvalid}
	}

	data, ok := f.files[name]
	if !ok {
		return nil, &fs.PathError{Op: "read", Path: name, Err: fs.ErrNotExist}
	}

	// Return an independent copy each call.
	cp := make([]byte, len(data))
	copy(cp, data)
	return cp, nil
}

// ReadDir implements fs.ReadDirFS.
func (f *embedFS) ReadDir(name string) ([]fs.DirEntry, error) {
	if !fs.ValidPath(name) {
		return nil, &fs.PathError{Op: "readdir", Path: name, Err: fs.ErrInvalid}
	}

	if name != "." && !f.isDir(name) {
		return nil, &fs.PathError{Op: "readdir", Path: name, Err: fs.ErrNotExist}
	}

	return f.readDir(name), nil
}

func (f *embedFS) isDir(name string) bool {
	prefix := name + "/"
	for p := range f.files {
		if strings.HasPrefix(p, prefix) {
			return true
		}
	}
	return false
}

func (f *embedFS) readDir(name string) []fs.DirEntry {
	seen := map[string]bool{}
	var entries []fs.DirEntry

	prefix := ""
	if name != "." {
		prefix = name + "/"
	}

	for p, data := range f.files {
		if prefix != "" && !strings.HasPrefix(p, prefix) {
			continue
		}

		rel := strings.TrimPrefix(p, prefix)
		if rel == "" {
			continue
		}

		parts := strings.SplitN(rel, "/", 2)
		childName := parts[0]

		if seen[childName] {
			continue
		}
		seen[childName] = true

		if len(parts) > 1 {
			entries = append(entries, &embedDirEntry{
				name:  childName,
				isDir: true,
			})
		} else {
			entries = append(entries, &embedDirEntry{
				name:  childName,
				isDir: false,
				size:  int64(len(data)),
			})
		}
	}

	// ReadDir entries are sorted by name.
	sort.Slice(entries, func(i, j int) bool {
		return entries[i].Name() < entries[j].Name()
	})
	return entries
}

// embedFile implements fs.File for a regular file.
type embedFile struct {
	name   string
	data   []byte
	offset int
}

func (f *embedFile) Stat() (fs.FileInfo, error) {
	return &embedFileInfo{name: f.name, size: int64(len(f.data))}, nil
}

func (f *embedFile) Read(b []byte) (int, error) {
	if f.offset >= len(f.data) {
		return 0, io.EOF
	}
	n := copy(b, f.data[f.offset:])
	f.offset += n
	return n, nil
}

func (f *embedFile) Close() error { return nil }

// embedDirFile implements fs.File and fs.ReadDirFile for a directory.
type embedDirFile struct {
	name    string
	fs      *embedFS
	dir     string
	entries []fs.DirEntry
	offset  int
}

func (f *embedDirFile) Stat() (fs.FileInfo, error) {
	return &embedFileInfo{name: f.name, isDir: true}, nil
}

func (f *embedDirFile) Read([]byte) (int, error) {
	return 0, &fs.PathError{Op: "read", Path: f.name, Err: fmt.Errorf("is a directory")}
}

func (f *embedDirFile) Close() error { return nil }

func (f *embedDirFile) ReadDir(n int) ([]fs.DirEntry, error) {
	if f.entries == nil {
		f.entries = f.fs.readDir(f.dir)
	}

	if n <= 0 {
		entries := f.entries[f.offset:]
		f.offset = len(f.entries)
		return entries, nil
	}

	if f.offset >= len(f.entries) {
		return nil, io.EOF
	}

	end := f.offset + n
	if end > len(f.entries) {
		end = len(f.entries)
	}
	entries := f.entries[f.offset:end]
	f.offset = end

	if f.offset >= len(f.entries) {
		return entries, io.EOF
	}
	return entries, nil
}

// embedDirEntry implements fs.DirEntry.
type embedDirEntry struct {
	name  string
	isDir bool
	size  int64
}

func (e *embedDirEntry) Name() string      { return e.name }
func (e *embedDirEntry) IsDir() bool       { return e.isDir }
func (e *embedDirEntry) Type() fs.FileMode {
	if e.isDir {
		return fs.ModeDir
	}
	return 0
}
func (e *embedDirEntry) Info() (fs.FileInfo, error) {
	return &embedFileInfo{name: e.name, isDir: e.isDir, size: e.size}, nil
}

// embedFileInfo implements fs.FileInfo.
type embedFileInfo struct {
	name  string
	size  int64
	isDir bool
}

func (fi *embedFileInfo) Name() string    { return fi.name }
func (fi *embedFileInfo) Size() int64     { return fi.size }
func (fi *embedFileInfo) Mode() fs.FileMode {
	if fi.isDir {
		return fs.ModeDir | 0555
	}
	return 0444
}
func (fi *embedFileInfo) ModTime() time.Time { return time.Time{} }
func (fi *embedFileInfo) IsDir() bool        { return fi.isDir }
func (fi *embedFileInfo) Sys() interface{}   { return nil }

// processEmbedDirectives walks root nodes to find embed-tagged variable
// declarations, resolves the patterns, and sets the embedded values directly
// in the interpreter's global frame. This must be called after GTA and
// resizeFrame, but before genGlobalVars, so that embed values are present
// before normal variable initialization runs.
func (interp *Interpreter) processEmbedDirectives(roots []*node, sc *scope) error {
	for _, root := range roots {
		for _, child := range root.child {
			if child.kind != varDecl {
				continue
			}
			for _, spec := range child.child {
				ed, ok := spec.meta.(*embedDir)
				if !ok || ed == nil {
					continue
				}

				// Determine source file directory for pattern resolution.
				srcFile := interp.fset.Position(spec.pos).Filename
				srcDir := path.Dir(srcFile)

				// Resolve patterns against the filesystem.
				files, err := resolveEmbedPatterns(interp.opt.filesystem, srcDir, ed.patterns)
				if err != nil {
					return spec.cfgErrorf("%v", err)
				}

				// Get the variable name(s) from the spec's children.
				// A valueSpec has children: [ident...] type
				// A defineStmt has children: [ident...] [type] [value...]
				for i := 0; i < spec.nleft; i++ {
					identNode := spec.child[i]
					sym, _, found := sc.lookup(identNode.ident)
					if !found {
						return spec.cfgErrorf("undefined: %s", identNode.ident)
					}

					if err := interp.setEmbedValue(sym, files, spec); err != nil {
						return err
					}
				}
			}
		}
	}
	return nil
}

// setEmbedValue sets the embedded value for a variable symbol based on its type.
func (interp *Interpreter) setEmbedValue(sym *symbol, files map[string][]byte, n *node) error {
	typ := sym.typ

	// Determine the target type category.
	switch {
	case isEmbedFSType(typ):
		// embed.FS type: create an embedFS with all files.
		efs := newEmbedFS(files)
		interp.frame.data[sym.index] = reflect.ValueOf(efs).Elem()
		return nil

	case isStringType(typ):
		// string type: must match exactly one file.
		if len(files) != 1 {
			return n.cfgErrorf("embedding into string: patterns match %d files, want 1", len(files))
		}
		for _, data := range files {
			interp.frame.data[sym.index] = reflect.ValueOf(string(data))
		}
		return nil

	case isByteSliceType(typ):
		// []byte type: must match exactly one file.
		if len(files) != 1 {
			return n.cfgErrorf("embedding into []byte: patterns match %d files, want 1", len(files))
		}
		for _, data := range files {
			cp := make([]byte, len(data))
			copy(cp, data)
			interp.frame.data[sym.index] = reflect.ValueOf(cp)
		}
		return nil

	default:
		return n.cfgErrorf("invalid type for //go:embed: must be string, []byte, or embed.FS")
	}
}

// isEmbedFSType checks if the type represents embed.FS.
func isEmbedFSType(typ *itype) bool {
	if typ == nil {
		return false
	}
	// Check for binary type wrapping embed.FS
	if typ.cat == valueT && typ.rtype != nil {
		return typ.rtype.PkgPath() == "embed" && typ.rtype.Name() == "FS"
	}
	// Check for selector expression "embed.FS" in source types
	if typ.name == "FS" && typ.path == "embed" {
		return true
	}
	return false
}

// isStringType checks if the type is string (or a named type with underlying string).
func isStringType(typ *itype) bool {
	if typ == nil {
		return false
	}
	return typ.cat == stringT || (typ.cat == valueT && typ.rtype != nil && typ.rtype.Kind() == reflect.String)
}

// isByteSliceType checks if the type is []byte.
func isByteSliceType(typ *itype) bool {
	if typ == nil {
		return false
	}
	if typ.cat == valueT && typ.rtype != nil {
		return typ.rtype.Kind() == reflect.Slice && typ.rtype.Elem().Kind() == reflect.Uint8
	}
	if typ.cat == arrayT && typ.val != nil {
		return typ.val.cat == uint8T
	}
	return false
}

