func TestEmbedFSOpen(t *testing.T) {
	files := map[string][]byte{
		"hello.txt":      []byte("hello"),
		"sub/world.txt":  []byte("world"),
	}
	efs := newEmbedFS(files)

	// Test Open file
	f, err := efs.Open("hello.txt")
	if err != nil {
		t.Fatal(err)
	}
	defer f.Close()

	data := make([]byte, 10)
	n, err := f.Read(data)
	if err != nil {
		t.Fatal(err)
	}
	if string(data[:n]) != "hello" {
		t.Errorf("got %q, want %q", string(data[:n]), "hello")
	}

	// Test ReadFile
	data2, err := efs.ReadFile("sub/world.txt")
	if err != nil {
		t.Fatal(err)
	}
	if string(data2) != "world" {
		t.Errorf("got %q, want %q", string(data2), "world")
	}

	// Verify ReadFile returns independent copy
	data2[0] = 'X'
	data3, err := efs.ReadFile("sub/world.txt")
	if err != nil {
		t.Fatal(err)
	}
	if string(data3) != "world" {
		t.Errorf("ReadFile did not return independent copy: got %q, want %q", string(data3), "world")
	}

	// Test Open directory
	d, err := efs.Open(".")
	if err != nil {
		t.Fatal(err)
	}
	defer d.Close()

	dirFile, ok := d.(fs.ReadDirFile)
	if !ok {
		t.Fatal("root dir does not implement ReadDirFile")
	}

	entries, err := dirFile.ReadDir(-1)
	if err != nil {
		t.Fatal(err)
	}
	if len(entries) != 2 {
		t.Fatalf("got %d entries, want 2", len(entries))
	}
	// Sorted by name
	if entries[0].Name() != "hello.txt" {
		t.Errorf("entries[0].Name() = %q, want %q", entries[0].Name(), "hello.txt")
	}
	if entries[1].Name() != "sub" || !entries[1].IsDir() {
		t.Errorf("entries[1] = (%q, isDir=%v), want (\"sub\", true)", entries[1].Name(), entries[1].IsDir())
	}

	// Test ReadDir
	subEntries, err := efs.ReadDir("sub")
	if err != nil {
		t.Fatal(err)
	}
	if len(subEntries) != 1 || subEntries[0].Name() != "world.txt" {
		t.Errorf("unexpected sub entries: %v", subEntries)
	}

	// Test NotExist
	_, err = efs.Open("nonexistent")
	if err == nil {
		t.Error("expected error for nonexistent file")
	}
}

