	"sync"
	"testing"
	"testing/fstest"
)

// testBuffer is a thread-safe buffer for capturing output in tests.
type testBuffer struct {
	mu  sync.Mutex
	buf bytes.Buffer
}

func (b *testBuffer) Write(p []byte) (n int, err error) {
	b.mu.Lock()
	defer b.mu.Unlock()
	return b.buf.Write(p)
}

